# OEIS sequence: A395400

from itertools import islice
from sympy import isprime, nextprime, primepi
def dot(p, q):
    s, t = str(p), str(q)
    return sum(int(si)*int(ti) for si, ti in zip(s, t)) if len(s) == len(t) else None
def agen(): # generator of terms
    p, q, n, adict = 2, 3, 3, dict()
    while True:
        v = dot(p, q)
        if v and isprime(v):
            vi = primepi(v)
            if vi not in adict:
                adict[vi] = p
                while n in adict:
                    yield adict[n]; n += 1
        p, q = q, nextprime(q)
print(list(islice(agen(), 50))) # _Michael S. Branicky_, Apr 22 2026

